function setSharpness(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/image/sharpness', { level: parseInt(value) });
}

// 设置白平衡模式
function setWhiteBalanceMode(mode) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    
    // v5.40: 处理三种模式
    var actualMode = mode;
    if (mode === 'auto_official') {
        actualMode = 'auto';
    } else if (mode === 'auto_astrohub') {
        // 暂未实现
        showToast('warning', '自动暂未实现');
        return;
    }
    
    apiPost('/api/v1/ptz/' + dev + '/image/whitebalance', { mode: actualMode })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', '白平衡: ' + (actualMode === 'auto' ? '自动（官方）' : '手动'));
                // v5.40: 更新 R/B 滑动条状态
                var wbRed = document.getElementById('wbRed');
                var wbBlue = document.getElementById('wbBlue');
                if (wbRed) wbRed.disabled = actualMode !== 'manual';
                if (wbBlue) wbBlue.disabled = actualMode !== 'manual';
            }
        });
}

// 设置白平衡增益 R/B
function setWhiteBalanceGain(channel, value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    
    // 更新显示
    if (channel === 'red') {
        var el = document.getElementById('wbRedVal');
        if (el) el.textContent = value;
    } else {
        var el = document.getElementById('wbBlueVal');
        if (el) el.textContent = value;
    }
    
    var key = channel === 'red' ? 'red_gain' : 'blue_gain';
    var label = channel === 'red' ? 'R (红增益)' : 'B (蓝增益)';
    
    // v6.56: 只发送增益值，不发送模式（模式已通过下拉菜单切换）
    apiPost('/api/v1/ptz/' + dev + '/image/whitebalance', { [key]: parseInt(value) })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', label + ': ' + value);
            }
        });
}

// 设置降噪
function setNoiseReduce(type, value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    
    var el = document.getElementById(type === 'spatial' ? 'dnrSpatialVal' : 'dnrTemporalVal');
    if (el) el.textContent = value;
    
    var key = type === 'spatial' ? 'spatial_level' : 'temporal_level';
    var label = type === 'spatial' ? '空域降噪' : '时域降噪';
    
    apiPost('/api/v1/ptz/' + dev + '/image/noisereduce', { [key]: parseInt(value) })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', label + ': ' + value);
            }
        });
}

// 加载曝光模式
function loadExposure(deviceIp) {
    // v7.54: 从 function.json 加载曝光模式选项
    if (!deviceFunctionData || !deviceFunctionData.functions || !deviceFunctionData.functions.exposure_mode) {
        console.warn('[Exposure] No function.json data available');
        return;
    }
    
    var exposureValues = deviceFunctionData.functions.exposure_mode.opt_values;
    if (!exposureValues || !Array.isArray(exposureValues) || exposureValues.length === 0) {
        console.warn('[Exposure] exposure_mode not supported');
        var select = document.getElementById('exposureMode');
        if (select) {
            select.innerHTML = '<option value="">-- 不支持 --</option>';
            select.disabled = true;
        }
        return;
    }
    
    // 填充选项
    var select = document.getElementById('exposureMode');
    if (select) {
        select.innerHTML = '';
        select.disabled = false;
        
        exposureValues.forEach(function(p) {
            var opt = document.createElement('option');
            opt.value = p;
            // 中文标签
            var labelMap = {
                'manual': '手动',
                'auto': '自动',
                'IrisFirst': '光圈优先',
                'ShutterFirst': '快门优先'
            };
            opt.textContent = labelMap[p] || p;
            select.appendChild(opt);
        });
    }
    
    // 获取当前值
    apiGet('/api/v1/ptz/' + deviceIp + '/image/exposure').then(function(r) {
        if (r && r.success && r.data) {
            if (select && r.data.mode) {
                select.value = r.data.mode;
                // 更新快门光圈禁用状态
                updateShutterIrisState();
            }
        }
    }).catch(function(e) {
        console.warn('[Exposure] Load failed:', e);
    });
}

// 设置曝光模式
function setExposureMode(mode) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    // v7.54: 支持多种曝光模式的中文显示
    var labelMap = {
        'manual': '手动',
        'auto': '自动',
        'IrisFirst': '光圈优先',
        'ShutterFirst': '快门优先'
    };
    apiPost('/api/v1/ptz/' + dev + '/image/exposure', { mode: mode })
        .then(function(r) {
            if (r && r.success) showToast('success', '曝光模式: ' + (labelMap[mode] || mode));
        });
    // v5.47: 更新快门光圈禁用状态
    updateShutterIrisState();
}

// v5.47: 更新快门光圈禁用状态
function updateShutterIrisState() {
    // v7.30: 检查设备是否连接
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        // 设备未连接，所有控件保持禁用
        return;
    }
    
    var exposureMode = document.getElementById('exposureMode');
    var shutterSelect = document.getElementById('shutterSpeed');
    var irisSelect = document.getElementById('irisLevel');
    var gainSlider = document.getElementById('gainLevel');
    if (!exposureMode || !shutterSelect || !irisSelect) return;
    
    // v7.54: 支持多种曝光模式
    var mode = exposureMode.value;
    var shutterEnabled = (mode === 'manual' || mode === 'ShutterFirst');
    var irisEnabled = (mode === 'manual' || mode === 'IrisFirst');
    var gainEnabled = (mode === 'manual' || mode === 'ShutterFirst' || mode === 'IrisFirst');
    shutterSelect.disabled = !shutterEnabled;
    irisSelect.disabled = !irisEnabled;
    if (gainSlider) gainSlider.disabled = !gainEnabled;
    
    // 禁用时灰色样式
    shutterSelect.style.opacity = shutterEnabled ? '1' : '0.5';
    irisSelect.style.opacity = irisEnabled ? '1' : '0.5';
    if (gainSlider) gainSlider.style.opacity = gainEnabled ? '1' : '0.5';
}

// 设置快门
function setShutterSpeed(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/image/shutter', { level: value })
        .then(function(r) {
            if (r && r.success) showToast('success', '快门: ' + value);
        });
}

// 设置光圈
function setIris(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev || !value) return;
    apiPost('/api/v1/ptz/' + dev + '/image/iris', { level: parseInt(value) })
        .then(function(r) {
            if (r && r.success) {
                var select = document.getElementById('irisLevel');
                var label = select.options[select.selectedIndex].text;
                showToast('success', '光圈: ' + label);
            }
        });
}

// v7.03: 设置增益
function setGain(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/image/gain', { level: parseInt(value) })
        .then(function(r) {
            if (r && r.success) showToast('success', '增益: ' + value);
        });
}

// v7.03: 加载增益
function loadGain(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/gain').then(function(r) {
        if (r && r.success && r.data) {
            var g = r.data;
            deviceImageParams.gain = g;
            
            var slider = document.getElementById('gainLevel');
            var valEl = document.getElementById('gainVal');
            
            if (slider) {
                slider.min = 0;
                slider.max = g.limit || 100;
                slider.value = g.current_level || 0;
            }
            if (valEl) valEl.textContent = g.current_level || 0;
        }
    }).catch(function(e) {
        console.warn('[Gain] Load failed:', e);
    });
}

