function togglePtzOsdSwitch(enabled) {
    ptzOsdEnabled = enabled;
    togglePtzOsd(enabled);
}

// v6.02: Info OSD 开关
function toggleInfoOsdSwitch(enabled) {
    infoOsdEnabled = enabled;
    toggleInfoOsd(enabled);
