        function adjustImage(param, value) {
            var dev = window.connectedDevice ? window.connectedDevice.ip : null;
            if (!dev) { showToast('warning', '请先选择设备'); return; }
            var labels = {brightness:'亮度',contrast:'对比度',saturation:'饱和度'};
            var label = labels[param] || param;

            // 调用 API 更新
            var body = {};
            body[param] = parseInt(value);
            apiPut('/api/v1/ptz/' + dev + '/image/settings', body).then(function(result) {
                if (result && result.success) {
                    showToast('success', label + '已设置为 ' + value);
                } else {
                    showToast('error', result ? result.message : '设置失败');
                }
            }).catch(function(e) {
                showToast('error', '设置异常: ' + e.message);
            });
        }
        function adjustImageStep(param, delta) {
            var sliderId = 'console' + param.charAt(0).toUpperCase() + param.slice(1);
            var slider = document.getElementById(sliderId);
            if (!slider) return;
            var newValue = Math.max(0, Math.min(100, parseInt(slider.value) + delta));
            slider.value = newValue;
            adjustImage(param, newValue);
        }
