// 从后端加载操作日志
function loadOperationLogs() {
    if (typeof apiGet === 'undefined') return;
    apiGet('/api/v1/log/operations/file?lines=50').then(function(r) {
        if (r && r.success && r.data) {
            var box = document.getElementById('ptzLogBox');
            if (!box) return;
            box.innerHTML = '';
            r.data.forEach(function(line) {
                var entry = document.createElement('div');
                entry.style.cssText = 'margin:2px 0;padding:2px 8px;font-size:12px;font-family:monospace';
                if (line.indexOf('ERROR') >= 0 || line.indexOf('FAILED') >= 0) {
                    entry.style.color = '#f85149';
                } else if (line.indexOf('WARN') >= 0) {
                    entry.style.color = '#d29922';
                } else {
                    entry.style.color = '#8b949e';
                }
                entry.textContent = line;
                box.appendChild(entry);
            });
        }
    }).catch(function(e) { console.warn('[LOG] load failed:', e); });
}
window.loadOperationLogs = loadOperationLogs;
