function loadDeviceImageParams(deviceIp) {
    if (!deviceIp) return;
    
    if (typeof apiGet === 'undefined') {
        console.error('[IMAGE] apiGet not defined');
        return;
    }
    
    console.log('[IMAGE] Loading image params for:', deviceIp);
    
    // v6.41: 重置状态
    functionCacheLoaded = false;
    deviceFunctionData = null;
    
    // v7.32: 必须有 function.json 才能启用画面控制
    apiGet('/api/v1/ptz/' + deviceIp + '/function').then(function(r) {
        if (r && r.success && r.data && r.data.functions) {
            deviceFunctionData = r.data;
            functionCacheLoaded = true;
            console.log('[IMAGE] function.json loaded, detected_at:', r.data.detected_at);
            enableImageControls();
            // 移除覆盖层
            removeFunctionOverlay();
            // 加载图像参数
            loadAllImageParams(deviceIp);
        } else {
            console.warn('[IMAGE] function.json not found - disabling image controls');
            // 禁用画面控制
            disableImageControls('请执行功能检测，以启用此功能');
            // 显示覆盖层
            showFunctionOverlay();
        }
    }).catch(function(e) {
        console.warn('[IMAGE] function.json failed:', e);
        disableImageControls('请执行功能检测，以启用此功能');
        showFunctionOverlay();
    });
}

