// v7.59: Operation log display (user actions)
function operationLog(msg, type='info') {
    const box = document.getElementById('operationLogBox');
    if (!box) { console.warn('[operationLog] operationLogBox not found'); return; }
    const time = new Date().toLocaleTimeString();
    const colors = {
        'info': '#8b949e',
        'success': '#3fb950',
        'error': '#f85149',
        'warning': '#d29922',
        'debug': '#58a6ff'
    };
    const icons = {
        'info': '○',
        'success': '●',
        'error': '×',
        'warning': '△',
        'debug': '◇'
    };
    const color = colors[type] || '#8b949e';
    const icon = icons[type] || '○';
    const entry = document.createElement('div');
    entry.style.cssText = 'color:' + color + ';margin:1px 0;padding:1px 6px;font-size:11px;font-family:monospace;line-height:1.3';
    entry.textContent = '[' + time + '] ' + icon + ' ' + msg;
    box.insertBefore(entry, box.firstChild);
    if (box.children.length > 50) box.removeChild(box.lastChild);
    console.log('[operationLog]', msg, type);

    // v6.40: 发送操作日志到后端
    if (typeof apiPost === 'function') {
        try {
            apiPost('/api/v1/log/operation', {
                level: type.toUpperCase(),
                module: 'web',
                action: 'ptz',
                detail: msg
            }).catch(function(e) { console.warn('[LOG] send failed:', e); });
        } catch(e) {}
    }
}
window.operationLog = operationLog;
