/**
 * MSE (Media Source Extensions) 视频播放器
 * 
 * 用于播放 RTSP 转 WebSocket 的 fMP4 流
 * 
 * Author: 开发工厂
 */

class MSEPlayer {
    constructor(videoElement, options = {}) {
        this.video = videoElement;
        this.ws = null;
        this.mediaSource = null;
        this.sourceBuffer = null;
        this.queue = [];
        this.mimeType = options.mimeType || 'video/mp4; codecs="avc1.64001f"';
        this.reconnectInterval = options.reconnectInterval || 3000;
        this.maxReconnectAttempts = options.maxReconnectAttempts || 5;
        this.reconnectAttempts = 0;
        this.isDestroyed = false;
    }

    /**
     * 连接到 RTSP 转 WebSocket 服务
     */
    connect(streamId, rtspUrl) {
        if (this.isDestroyed) return;

        const wsUrl = `ws://${window.location.host}/ws/rtsp/${streamId}?rtsp_url=${encodeURIComponent(rtspUrl)}`;

        try {
            this.ws = new WebSocket(wsUrl);
            this.ws.binaryType = 'arraybuffer';

            this.ws.onopen = () => {
                console.log('[MSE] WebSocket connected');
                this.reconnectAttempts = 0;
                this._initMediaSource();
            };

            this.ws.onmessage = (event) => {
                this._handleData(event.data);
            };

            this.ws.onerror = (error) => {
                console.error('[MSE] WebSocket error:', error);
                this._tryReconnect(streamId, rtspUrl);
            };

            this.ws.onclose = () => {
                console.log('[MSE] WebSocket closed');
                this._tryReconnect(streamId, rtspUrl);
            };
        } catch (error) {
            console.error('[MSE] Connect failed:', error);
            this._tryReconnect(streamId, rtspUrl);
        }
    }

    /**
     * 初始化 MediaSource
     */
    _initMediaSource() {
        if (!('MediaSource' in window)) {
            console.error('[MSE] MediaSource not supported');
            return;
        }

        this.mediaSource = new MediaSource();
        this.video.src = URL.createObjectURL(this.mediaSource);

        this.mediaSource.addEventListener('sourceopen', () => {
            console.log('[MSE] MediaSource opened');

            try {
                this.sourceBuffer = this.mediaSource.addSourceBuffer(this.mimeType);

                this.sourceBuffer.addEventListener('updateend', () => {
                    this._processQueue();
                });

                this.sourceBuffer.addEventListener('error', (e) => {
                    console.error('[MSE] SourceBuffer error:', e);
                });

                // 开始处理队列中的数据
                this._processQueue();
            } catch (error) {
                console.error('[MSE] addSourceBuffer failed:', error);
            }
        });

        this.mediaSource.addEventListener('error', (e) => {
            console.error('[MSE] MediaSource error:', e);
        });

        this.mediaSource.addEventListener('sourceclose', () => {
            console.log('[MSE] MediaSource closed');
        });
    }

    /**
     * 处理接收到的数据
     */
    _handleData(data) {
        if (!this.sourceBuffer || this.sourceBuffer.updating) {
            this.queue.push(data);
        } else {
            try {
                this.sourceBuffer.appendBuffer(new Uint8Array(data));
            } catch (error) {
                console.error('[MSE] appendBuffer failed:', error);
                this.queue.push(data);
            }
        }
    }

    /**
     * 处理队列中的数据
     */
    _processQueue() {
        if (!this.sourceBuffer || this.sourceBuffer.updating || this.queue.length === 0) {
            return;
        }

        const data = this.queue.shift();
        try {
            this.sourceBuffer.appendBuffer(new Uint8Array(data));
        } catch (error) {
            console.error('[MSE] appendBuffer from queue failed:', error);
            // 重新放入队列
            this.queue.unshift(data);
        }
    }

    /**
     * 尝试重连
     */
    _tryReconnect(streamId, rtspUrl) {
        if (this.isDestroyed) return;

        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
            console.error('[MSE] Max reconnect attempts reached');
            return;
        }

        this.reconnectAttempts++;
        console.log(`[MSE] Reconnecting (${this.reconnectAttempts}/${this.maxReconnectAttempts})...`);

        setTimeout(() => {
            this.connect(streamId, rtspUrl);
        }, this.reconnectInterval);
    }

    /**
     * 停止播放
     */
    stop() {
        this.isDestroyed = true;

        if (this.ws) {
            this.ws.close();
            this.ws = null;
        }

        if (this.mediaSource && this.mediaSource.readyState === 'open') {
            try {
                this.mediaSource.endOfStream();
            } catch (e) {
                // ignore
            }
        }

        if (this.video.src) {
            URL.revokeObjectURL(this.video.src);
            this.video.src = '';
        }

        this.queue = [];
        console.log('[MSE] Player stopped');
    }

    /**
     * 检查是否支持 MSE
     */
    static isSupported() {
        return 'MediaSource' in window;
    }
}

