// v7.61: 启动 MSE 播放
function startMSEPlay(iStreamType, iChannelID) {
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.error('[MSE] No device connected');
        return;
    }

    // 检查 MSE 支持
    if (!window.MSEPlayer || !window.MSEPlayer.isSupported()) {
        console.error('[MSE] MSE not supported');
        if (typeof mediaLog === 'function') mediaLog('MSE not supported', 'error');
        return;
    }

    // 构建 RTSP URL
    var ip = window.connectedDevice.ip;
    var rtspPort = 554;  // 默认 RTSP 端口
    var channel = iChannelID;
    var streamSuffix = iStreamType === 1 ? '01' : (iStreamType === 2 ? '02' : '03');
    var rtspUrl = 'rtsp://' + window.connectedDevice.username + ':' + window.connectedDevice.password + '@' + ip + ':' + rtspPort + '/Streaming/Channels/' + channel + '0' + streamSuffix;

    console.log('[MSE] RTSP URL:', rtspUrl);

    // 隐藏 WASM 容器，显示 MSE 视频
    var divPlugin = document.getElementById('divPlugin');
    var mseVideo = document.getElementById('mseVideo');
    if (divPlugin) divPlugin.style.display = 'none';
    if (mseVideo) mseVideo.style.display = 'block';

    // 停止旧的 MSE 播放器
    if (g_msePlayer) {
        g_msePlayer.stop();
    }

    // 创建新的 MSE 播放器
    g_msePlayer = new window.MSEPlayer(mseVideo);
    g_useMSE = true;

    // 连接
    var streamId = 'stream_' + Date.now();
    g_msePlayer.connect(streamId, rtspUrl);

    if (typeof mediaLog === 'function') mediaLog('MSE playing...', 'info');
    if (window.updateWasmStatus) window.updateWasmStatus('playing');
    g_bPlaying2 = true;
}

