# v7.61: RTSP to WebSocket converter
from src.stream.rtsp_ws import converter as rtsp_converter

@app.websocket("/ws/rtsp/{stream_id}")
async def rtsp_websocket(websocket: WebSocket, stream_id: str):
    """RTSP to WebSocket endpoint
    
    Query params:
    - rtsp_url: RTSP stream URL
    """
    await websocket.accept()
    
    rtsp_url = websocket.query_params.get("rtsp_url")
    if not rtsp_url:
        await websocket.send_text('{"error": "Missing rtsp_url parameter"}')
        await websocket.close()
        return
    
    try:
        await rtsp_converter.start_stream(stream_id, rtsp_url, websocket)
    except Exception as e:
        logger.error(f"RTSP stream error: {e}")
        try:
            await websocket.send_text(f'{{"error": "{str(e)}"}}')
        except:
            pass
    finally:
        rtsp_converter.stop_stream(stream_id)

